<?php
namespace Zclone\services;
use Zclone\Core\Database; use Zclone\Core\EventDispatcher;
final class BuildingService { public const BUILDINGS=['metal_mine','crystal_mine','deuterium_synthesizer','solar_plant','fusion_reactor','robotics_factory','shipyard','research_lab','nanite_factory','alliance_depot']; public function __construct(private Database $db, private EventDispatcher $events) {} public function cost(string $type,int $level): array { $base=['metal_mine'=>[60,15,0],'crystal_mine'=>[48,24,0],'deuterium_synthesizer'=>[225,75,0],'solar_plant'=>[75,30,0],'shipyard'=>[400,200,100]][$type] ?? [100,50,25]; return ['metal'=>ceil($base[0]*pow(1.5,$level)),'crystal'=>ceil($base[1]*pow(1.6,$level)),'deuterium'=>ceil($base[2]*pow(1.4,$level))]; } public function enqueue(int $planetId,string $type): void { if (!in_array($type,self::BUILDINGS,true)) throw new \InvalidArgumentException('bad building'); $level=(int)($this->db->one('select level from planet_buildings where planet_id=? and type=?',[$planetId,$type])['level'] ?? 0); $seconds=max(30, (int)(array_sum($this->cost($type,$level))/20)); $this->db->exec("insert into build_queue (planet_id,type,level,finish_at) values (?,?,?,now() + (? || ' seconds')::interval)",[$planetId,$type,$level+1,$seconds]); $this->events->dispatch('BuildingQueued',['planet_id'=>$planetId,'type'=>$type]); } }
